function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const n = points.length;
    const yMap = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y)!.push(x);
    }

    let result = 0;

    // Iterate through each y-coordinate
    for (const [y1, xs1] of yMap.entries()) {
        // Get the count of points at y1
        const count1 = xs1.length;
        // Iterate through another y-coordinate
        for (const [y2, xs2] of yMap.entries()) {
            if (y1 === y2) continue;
            const count2 = xs2.length;

            // Calculate the number of ways to choose 2 points from each y-coordinate
            // and multiply them to get the number of rectangles with horizontal sides
            // (each pair of points from y1 and y2 forms a horizontal side)
            const ways = (count1 * (count1 - 1) / 2) * (count2 * (count2 - 1) / 2);
            result = (result + ways) % MOD;
        }
    }

    return result;
}

